const aiResp = $('Gate Evaluator AI').first().json;
let raw = aiResp.output || aiResp.text || '';
let gates = {};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON');
  gates = JSON.parse(m[0]);
} catch(e) {
  gates = { gate1_apac_mandate:'unknown', gate1_evidence:'AI parse error',
    gate2_physical_ops:'unknown', gate2_evidence:'AI parse error',
    gate3_right_size:'unknown', gate3_evidence:'AI parse error',
    gate3_swf_bypass:false, gate3_aum_in_billions:null,
    gate4_apac_deal_flow:'unknown', gate4_evidence:'AI parse error', overall_confidence:0 };
}

const isPass = v => (v||'').toLowerCase() === 'pass';
const isFail = v => (v||'').toLowerCase() === 'fail';
const isUnk  = v => (v||'').toLowerCase() === 'unknown';

const g1 = gates.gate1_apac_mandate   || 'unknown';
const g2 = gates.gate2_physical_ops   || 'unknown';
const g3 = gates.gate3_right_size     || 'unknown';
const g4 = gates.gate4_apac_deal_flow || 'unknown';

// ── NEW RULE ──────────────────────────────────────────────
// QUALIFIED   = Gate 1 PASS AND Gate 2 PASS (both mandatory)
// DISQUALIFIED = Gate 1 FAIL OR Gate 2 FAIL (either fails = out)
// Gate 3 and Gate 4 = evidence only, do not affect decision
// ─────────────────────────────────────────────────────────
let qualified     = false;
let strong_fit    = false;
let manual_review = false;
let decision      = 'disqualified';
let discard_reason = '';

if (isPass(g1) && isPass(g2)) {
  qualified  = true;
  strong_fit = true;
  decision   = 'qualified';
} else {
  // At least one of Gate 1 or Gate 2 failed
  const reasons = [];
  if (!isPass(g1)) reasons.push('Gate 1 failed — ' + (gates.gate1_evidence || 'no APAC mandate found'));
  if (!isPass(g2)) reasons.push('Gate 2 failed — ' + (gates.gate2_evidence || 'no physical ops portfolio found'));
  discard_reason = reasons.join(' | ');
  decision = 'disqualified';
}

const firm = $('JSON Cleaner2').first().json;

return [{ json: {
  pe_firm_name:          firm.pe_firm_name,
  website_url:           firm.website_url,
  company_linkedin_url:  firm.company_linkedin_url,
  company_country:       firm.company_country,
  industry:              firm.industry,
  headcount:             firm.headcount,
  scrape_quality:        firm.scrape_quality,
  pages_scraped:         JSON.stringify(firm.pages_scraped || []),
  keywords:              firm.keywords,
  text_sample_for_ai:    firm.text_sample_for_ai,
  apac_offices_detected: JSON.stringify(firm.apac_offices_detected || []),
  sectors_detected:      JSON.stringify(firm.sectors_detected || []),
  team_page_url:         firm.team_page_url,
  portfolio_page_url:    firm.portfolio_page_url,
  centralized_phrases:   JSON.stringify(firm.centralized_phrases || []),
  network_phrases:       JSON.stringify(firm.network_phrases || []),
  gate1_apac_mandate:    g1,
  gate1_evidence:        gates.gate1_evidence || '',
  gate2_physical_ops:    g2,
  gate2_evidence:        gates.gate2_evidence || '',
  gate3_right_size:      g3,
  gate3_evidence:        gates.gate3_evidence || '',
  gate3_swf_bypass:      gates.gate3_swf_bypass || false,
  aum_in_billions:       gates.gate3_aum_in_billions || null,
  gate4_apac_deal_flow:  g4,
  gate4_evidence:        gates.gate4_evidence || '',
  qualified:             qualified,
  strong_fit:            strong_fit,
  manual_review:         manual_review,
  decision:              decision,
  discard_reason:        discard_reason,
  phase1_confidence:     gates.overall_confidence || 0,
  run_date:              new Date().toISOString().split('T')[0],
  w1_status:             'done'
}}];

const firmMap = {};
for (const item of $input.all()) {
  const raw = item.json;
  const name = (raw['Company Name'] || '').trim();
  if (!name || firmMap[name]) continue;
  firmMap[name] = {
    pe_firm_name:         name,
    website_url:          (raw['Website'] || '').trim(),
    company_linkedin_url: (raw['Company Linkedin Url'] || '').trim(),
    headcount:            raw['# Employees'] || null,
    company_country:      (raw['Company Country'] || '').trim(),
    company_city:         (raw['Company City'] || '').trim(),
    keywords:             (raw['Keywords'] || '').toLowerCase(),
    industry:             (raw['Industry'] || '').toLowerCase()
  };
}
const out = Object.values(firmMap).map(f => ({ json: f }));
if (!out.length) throw new Error('No firms found. Check columns: Company Name, Website, Company Linkedin Url, # Employees, Company Country');
return out;

const excludeInd = ['banking','bank','insurance','mutual fund',
  'asset management','wealth management','hedge fund','reit',
  'real estate investment trust','real estate fund'];
const excludeKw = ['mutual fund','hedge fund','wealth management',
  'asset management','reit','insurance carrier'];

return $input.all().map(item => {
  const ind = (item.json.industry || '').toLowerCase();
  const kw  = (item.json.keywords || '').toLowerCase();
  let matched = null;
  for (const ex of excludeInd) { if (ind.includes(ex)) { matched = ex; break; } }
  if (!matched) for (const ex of excludeKw) { if (kw.includes(ex)) { matched = ex; break; } }
  return { json: {
    ...item.json,
    scope_status:   matched ? 'out_of_scope' : 'in_scope',
    discard_reason: matched ? 'Out of scope: ' + matched : null
  }};
});

const firm = $input.first().json;
let base = firm.website_url || '';
if (!base) return [{ json: { ...firm, pages_to_crawl: [], base_url: '' } }];
if (!base.startsWith('http')) base = 'https://' + base;
base = base.replace(/\/$/, '');
const suffixes = ['','/team','/our-team','/people','/about','/about-us',
  '/approach','/value-creation','/portfolio','/investments','/operating-group'];
return [{ json: { ...firm, base_url: base,
  pages_to_crawl: suffixes.map(s => ({ url: base + s, page_type: s || 'homepage' })) }}];

const firm = $input.first().json;
const pages = firm.pages_to_crawl || [];
if (!pages.length) return [{ json: { ...firm, url: firm.base_url || '', page_type: 'homepage' } }];
return pages.map(p => ({ json: { ...firm, url: p.url, page_type: p.page_type } }));

const httpItems = $input.all();
const firmItems = $('Split Pages to Crawl2').all();
return httpItems.map((item, i) => {
  const firm = firmItems[i]?.json || {};
  const body = item.json.data || item.json.body || '';
  return { json: { ...firm, body: typeof body === 'string' ? body : JSON.stringify(body) } };
});

const items = $input.all();
if (!items.length) return [{ json: { crawl_status: 'failed', pages_fetched: [] } }];
const first = items[0].json;
const pages = items
  .map(i => ({ url: i.json.url||'', page_type: i.json.page_type||'unknown', body: i.json.body||'' }))
  .filter(p => p.body && p.body.length > 50);
return [{ json: { ...first, pages_fetched: pages, crawl_status: pages.length > 0 ? 'success' : 'failed' } }];

const firm = $input.first().json;

function stripHtml(html) {
  if (!html || typeof html !== 'string') return '';
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ').trim().slice(0, 8000);
}

const centralizedPhrases = ['team of','full-time','in-house operating','dedicated team',
  'embedded professionals','our operating team','portfolio operations team',
  'value creation team','operating group','capstone','portfolio group','gps team'];
const networkPhrases = ['network of advisors','external advisors','industrial advisors',
  'consulting partners','part-time affiliates','advisor network','executive network'];
const apacLocations = ['singapore','hong kong','mumbai','jakarta','sydney','tokyo',
  'beijing','shanghai','seoul','kuala lumpur','bangkok','taipei','melbourne',
  'osaka','new delhi','manila'];
const physicalSectors = ['manufacturing','industrials','infrastructure','logistics','energy',
  'consumer goods','healthcare','real assets','chemicals','automotive','packaging',
  'electronics','pharma','medical devices','building materials','food','beverage','supply chain'];

const rawPages = (firm.pages_fetched || []).map(p => ({
  url: p.url||'', page_type: p.page_type||'unknown', text: stripHtml(p.body||'')
}));
if (!rawPages.length && firm.body)
  rawPages.push({ url: firm.base_url||'', page_type: 'homepage', text: stripHtml(firm.body) });

const allText = rawPages.map(p => p.text).join(' ').toLowerCase();
const teamPage      = rawPages.find(p => ['team','our-team','people'].includes(p.page_type));
const portfolioPage = rawPages.find(p => ['portfolio','investments'].includes(p.page_type));

return [{ json: {
  pe_firm_name:          firm.pe_firm_name,
  website_url:           firm.website_url,
  base_url:              firm.base_url || firm.website_url,
  company_linkedin_url:  firm.company_linkedin_url,
  headcount:             firm.headcount,
  company_country:       firm.company_country,
  company_city:          firm.company_city,
  keywords:              firm.keywords,
  industry:              firm.industry,
  pages_scraped:         rawPages.map(p => p.url).filter(Boolean),
  scrape_quality:        allText.length < 500 ? 'failed' : allText.length < 2000 ? 'partial' : 'good',
  centralized_phrases:   centralizedPhrases.filter(p => allText.includes(p)),
  network_phrases:       networkPhrases.filter(p => allText.includes(p)),
apac_offices_detected: (() => {
  const fromText = apacLocations.filter(l => allText.includes(l));
  const apacCountries = ['singapore','hong kong','india','indonesia','australia',
    'japan','china','south korea','malaysia','thailand','taiwan','vietnam',
    'philippines','myanmar','cambodia','bangladesh','sri lanka','pakistan','nepal','brunei'];
  const countryLower = (firm.company_country || '').toLowerCase();
  const fromCountry = apacCountries.filter(c => countryLower.includes(c));
  return [...new Set([...fromText, ...fromCountry])];
})(),
  sectors_detected:      physicalSectors.filter(s => allText.includes(s)),
  team_page_url:         teamPage ? teamPage.url : null,
  portfolio_page_url:    portfolioPage ? portfolioPage.url : null,
  text_sample_for_ai:    allText.slice(0, 6000)
}}];
